     1|/**
     2| * IVX Public Feature Handlers — registered under /api/ivx/*
     3| *
     4| * Covers: properties, members dashboard, investors dashboard,
     5| * CRM, JV deals, property admin, media, instagram cards.
     6| */
     7|const DEPLOYMENT_MARKER = 'ivx-public-features-api-v1-2026-07-01';
     8|
     9|// ── Supabase ───────────────────────────────────────────────────────────────
    10|let _sb: any = null;
    11|async function getSB() {
    12|  if (_sb) return _sb;
    13|  const { createClient } = await import('@supabase/supabase-js');
    14|  const url = (process.env.EXPO_PUBLIC_SUPABASE_URL || process.env.SUPABASE_URL || '').trim();
    15|  const key = (process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.SUPABASE_SERVICE_KEY || '').trim();
    16|  _sb = createClient(url, key, { auth: { autoRefreshToken: false, persistSession: false } });
    17|  return _sb;
    18|}
    19|
    20|function json(data: unknown, status = 200): Response {
    21|  return new Response(JSON.stringify(data), {
    22|    status,
    23|    headers: { 'Content-Type': 'application/json', 'Cache-Control': 'no-store', 'Access-Control-Allow-Origin': '*', 'Access-Control-Allow-Headers': 'Content-Type, Authorization, apikey', 'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS' },
    24|  });
    25|}
