    27|async function readBody(req: Request): Promise<Record<string, unknown>> {
    28|  try { return await req.json() as Record<string, unknown>; } catch { return {}; }
    29|}
    30|
    31|function safeStr(v: unknown, fallback = ''): string { return typeof v === 'string' ? v.trim() : fallback; }
    32|
    33|export const publicFeatureOptions = (): Response => {
    34|  return new Response(null, { status: 204, headers: { 'Access-Control-Allow-Origin': '*', 'Access-Control-Allow-Headers': 'Content-Type, Authorization, apikey', 'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS' } });
    35|};
    36|
    37|// ── Featured Properties ────────────────────────────────────────────────────
    38|export async function handleFeaturedProperties(req: Request): Promise<Response> {
    39|  try {
    40|    const sb = await getSB();
    41|    const { data, error } = await sb.from('properties').select('*').eq('is_featured', true).order('created_at', { ascending: false }).limit(20);
    42|    if (error) return json({ error: error.message, deploymentMarker: DEPLOYMENT_MARKER }, 500);
    43|    return json({ properties: data || [], count: data?.length || 0, deploymentMarker: DEPLOYMENT_MARKER });
    44|  } catch (err: any) { return json({ error: err.message, deploymentMarker: DEPLOYMENT_MARKER }, 500); }
    45|}
    46|
    47|// ── Property Details ──────────────────────────────────────────────────────
    48|export async function handlePropertyDetails(req: Request, propertyId: string): Promise<Response> {
    49|  try {
    50|    const sb = await getSB();
    51|    const { data, error } = await sb.from('properties').select('*').eq('id', propertyId).single();
    52|    if (error) return json({ error: error.message, deploymentMarker: DEPLOYMENT_MARKER }, 404);
    53|    return json({ property: data, deploymentMarker: DEPLOYMENT_MARKER });
    54|  } catch (err: any) { return json({ error: err.message, deploymentMarker: DEPLOYMENT_MARKER }, 500); }
